import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(position1, position2):
        return np.linalg.norm(position1 - position2) / truck_speed

    def congestion_effect(candidate_pos):
        return np.exp(-np.min([np.linalg.norm(candidate_pos - pos) for pos in all_truck_pos if not np.array_equal(pos, candidate_pos)]))

    def dynamic_score(candidate_index):
        candidate_pos = unvisited_customers[candidate_index]
        travel_time = calculate_travel_time(cur_truck_pos, candidate_pos)
        arrival_time = current_time + travel_time
        start_time, end_time = time_windows[candidate_index]

        if arrival_time <= start_time:
            time_penalty = start_time - arrival_time
        elif arrival_time > end_time:
            time_penalty = np.inf
        else:
            time_penalty = 0

        distance_weight = np.linalg.norm(candidate_pos - cur_truck_pos)
        congestion_penalty = congestion_effect(candidate_pos)

        return -(distance_weight + time_penalty * 0.5 + congestion_penalty)

    best_score = -np.inf
    best_node = None
    for index in range(len(unvisited_customers)):
        score = dynamic_score(index)
        if score > best_score:
            best_score = score
            best_node = index

    return best_node

